package com.establo.service;
import com.establo.dto.*;import com.establo.entity.*;import com.establo.exception.ResourceNotFoundException;import com.establo.repository.*;import lombok.RequiredArgsConstructor;import org.springframework.data.domain.*;import org.springframework.stereotype.Service;import java.util.List;
@Service @RequiredArgsConstructor public class SupplyService {
 private final InventoryItemRepository inventory;private final FeedingPlanRepository plans;private final HorseService horses;
 public List<InventoryItemDto> inventory(){return inventory.findAll().stream().map(this::itemDto).toList();}public InventoryItemDto saveItem(Long id,InventoryItemDto d){var x=id==null?new InventoryItem():inventory.findById(id).orElseThrow(()->new ResourceNotFoundException("Insumo no encontrado"));x.setName(d.name());x.setCategory(d.category());x.setQuantity(d.quantity());x.setMinimumStock(d.minimumStock());x.setUnit(d.unit());return itemDto(inventory.save(x));}public void deleteItem(Long id){inventory.deleteById(id);} public List<FeedingPlanDto> plans(){return plans.findAll().stream().map(this::planDto).toList();}public FeedingPlanDto savePlan(Long id,FeedingPlanDto d){var p=id==null?new FeedingPlan():plans.findById(id).orElseThrow(()->new ResourceNotFoundException("Plan no encontrado"));p.setHorse(horses.entity(d.horseId()));p.setFeedType(d.feedType());p.setQuantity(d.quantity());p.setUnit(d.unit());p.setScheduleTime(d.scheduleTime());p.setNotes(d.notes());return planDto(plans.save(p));}public void deletePlan(Long id){plans.deleteById(id);}
 public Page<InventoryItemDto> searchInventory(String q,String category,Boolean lowStock,Pageable pageable){var filtered=inventory().stream().filter(i->q==null||q.isBlank()||i.name().toLowerCase().contains(q.toLowerCase())).filter(i->category==null||category.isBlank()||i.category().equalsIgnoreCase(category)).filter(i->lowStock==null||i.lowStock().equals(lowStock)).toList();int start=(int)Math.min(pageable.getOffset(),filtered.size());int end=Math.min(start+pageable.getPageSize(),filtered.size());return new PageImpl<>(filtered.subList(start,end),pageable,filtered.size());}
 private InventoryItemDto itemDto(InventoryItem x){return new InventoryItemDto(x.getId(),x.getName(),x.getCategory(),x.getQuantity(),x.getMinimumStock(),x.getUnit(),x.isLowStock());}private FeedingPlanDto planDto(FeedingPlan p){return new FeedingPlanDto(p.getId(),p.getHorse().getId(),p.getHorse().getName(),p.getFeedType(),p.getQuantity(),p.getUnit(),p.getScheduleTime(),p.getNotes());}
}
